import{_ as t,o as a,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"205. Overtime In Lieu","description":"","frontmatter":{"title":"205. Overtime In Lieu","eba":"Mental Health Services 2024-2028","topics":["hours","overtime","wages"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/hours-of-work/205-overtime-in-lieu.md","filePath":"ebas/mental-health/management-admin/hours-of-work/205-overtime-in-lieu.md"}'),i={name:"ebas/mental-health/management-admin/hours-of-work/205-overtime-in-lieu.md"};function n(s,e,m,l,h,u){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_205-overtime-in-lieu" tabindex="-1">205. Overtime In Lieu <a class="header-anchor" href="#_205-overtime-in-lieu" aria-label="Permalink to &quot;205. Overtime In Lieu&quot;">​</a></h1><p><strong>205.1</strong> An Employee may elect, with the consent of the Employer, to take time off in lieu of payment for overtime at a time or times agreed with the Employer.</p><p><strong>205.2</strong> Overtime taken as time off during ordinary time hours shall be taken at the penalty time rate. That is, one- and one-half hours off or two hours off, as the case may be, for each overtime hour worked.</p><p><strong>205.3</strong> An Employer shall provide payment at the appropriate overtime rate where time off in lieu has not been taken within four (4) weeks of accrual.</p><p><strong>205.4</strong> For the purposes of this clause, in accruing or calculating payment of overtime, each period of overtime shall stand alone.</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',6)])])}const c=t(i,[["render",n]]);export{f as __pageData,c as default};
